-- ═══════════════════════════════════════════════════════════
-- CampusCore University ERP — MySQL (Optimized — No Subqueries)
-- All IDs hardcoded for fast import (~30 seconds)
-- Import into Railway MySQL database
-- ═══════════════════════════════════════════════════════════
-- CREDENTIALS:
--   Admin  : admin@university.edu   / admin@123
--   Admin2 : admin2@university.edu  / admin2@123
--   Teacher: <email>                / teacher{N}@123
--   Student: <email>                / {RollNumber}@student123
-- ═══════════════════════════════════════════════════════════

SET FOREIGN_KEY_CHECKS = 0;
SET SQL_MODE = 'NO_AUTO_VALUE_ON_ZERO';
SET time_zone = '+00:00';

-- ================================================================
-- SCHEMA
-- ================================================================

CREATE TABLE IF NOT EXISTS `Departments` (
    `DepartmentID`   INT NOT NULL AUTO_INCREMENT,
    `DepartmentName` VARCHAR(150) NOT NULL,
    `DepartmentCode` VARCHAR(20)  NOT NULL,
    `CreatedAt`      DATETIME NOT NULL DEFAULT NOW(),
    PRIMARY KEY (`DepartmentID`),
    UNIQUE KEY `uq_dept_name` (`DepartmentName`),
    UNIQUE KEY `uq_dept_code` (`DepartmentCode`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

CREATE TABLE IF NOT EXISTS `Users` (
    `UserID`       INT NOT NULL AUTO_INCREMENT,
    `UserType`     ENUM('Admin','Teacher','Student') NOT NULL,
    `UserCode`     VARCHAR(50)  NOT NULL,
    `FullName`     VARCHAR(150) NOT NULL,
    `Email`        VARCHAR(150) NULL,
    `Phone`        VARCHAR(20)  NULL,
    `DateOfBirth`  DATE NULL,
    `Gender`       VARCHAR(10)  NULL,
    `FatherName`   VARCHAR(150) NULL,
    `MotherName`   VARCHAR(150) NULL,
    `PasswordHash` VARCHAR(255) NOT NULL,
    `IsFirstLogin` TINYINT(1)   NOT NULL DEFAULT 1,
    `DepartmentID` INT NULL,
    `Semester`     INT NULL,
    `JoinDate`     DATE NULL,
    `Address`      VARCHAR(255) NULL,
    `IsActive`     TINYINT(1)   NOT NULL DEFAULT 1,
    `CreatedAt`    DATETIME NOT NULL DEFAULT NOW(),
    `UpdatedAt`    DATETIME NOT NULL DEFAULT NOW(),
    PRIMARY KEY (`UserID`),
    UNIQUE KEY `uq_user_code` (`UserCode`),
    KEY `idx_users_type` (`UserType`),
    KEY `idx_users_dept` (`DepartmentID`),
    CONSTRAINT `fk_users_dept` FOREIGN KEY (`DepartmentID`) REFERENCES `Departments`(`DepartmentID`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

CREATE TABLE IF NOT EXISTS `Subjects` (
    `SubjectID`    INT NOT NULL AUTO_INCREMENT,
    `SubjectName`  VARCHAR(200) NOT NULL,
    `SubjectCode`  VARCHAR(20)  NOT NULL,
    `Credits`      INT NULL,
    `DepartmentID` INT NOT NULL,
    `Semester`     INT NOT NULL,
    `CreatedAt`    DATETIME NOT NULL DEFAULT NOW(),
    PRIMARY KEY (`SubjectID`),
    UNIQUE KEY `uq_subject_code` (`SubjectCode`),
    KEY `idx_subj_dept` (`DepartmentID`),
    CONSTRAINT `fk_subj_dept` FOREIGN KEY (`DepartmentID`) REFERENCES `Departments`(`DepartmentID`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

CREATE TABLE IF NOT EXISTS `Classes` (
    `ClassID`      INT NOT NULL AUTO_INCREMENT,
    `ClassName`    VARCHAR(100) NOT NULL,
    `DepartmentID` INT NOT NULL,
    `Semester`     INT NOT NULL,
    `Section`      VARCHAR(10)  NOT NULL DEFAULT 'A',
    `AcademicYear` VARCHAR(20)  NULL,
    `CreatedAt`    DATETIME NOT NULL DEFAULT NOW(),
    PRIMARY KEY (`ClassID`),
    KEY `idx_class_dept` (`DepartmentID`),
    CONSTRAINT `fk_class_dept` FOREIGN KEY (`DepartmentID`) REFERENCES `Departments`(`DepartmentID`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

CREATE TABLE IF NOT EXISTS `TeacherSubjects` (
    `TeacherSubjectID` INT NOT NULL AUTO_INCREMENT,
    `TeacherID`        INT NOT NULL,
    `SubjectID`        INT NOT NULL,
    `ClassID`          INT NOT NULL,
    `AcademicYear`     VARCHAR(20) NULL,
    `AssignedAt`       DATETIME NOT NULL DEFAULT NOW(),
    PRIMARY KEY (`TeacherSubjectID`),
    KEY `idx_ts_teacher` (`TeacherID`),
    KEY `idx_ts_subject` (`SubjectID`),
    KEY `idx_ts_class` (`ClassID`),
    CONSTRAINT `fk_ts_teacher` FOREIGN KEY (`TeacherID`) REFERENCES `Users`(`UserID`),
    CONSTRAINT `fk_ts_subject` FOREIGN KEY (`SubjectID`) REFERENCES `Subjects`(`SubjectID`),
    CONSTRAINT `fk_ts_class`   FOREIGN KEY (`ClassID`)   REFERENCES `Classes`(`ClassID`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

CREATE TABLE IF NOT EXISTS `StudentEnrollments` (
    `EnrollmentID` INT NOT NULL AUTO_INCREMENT,
    `StudentID`    INT NOT NULL,
    `ClassID`      INT NULL,
    `SubjectID`    INT NULL,
    `AcademicYear` VARCHAR(20) NULL,
    `EnrolledAt`   DATETIME NOT NULL DEFAULT NOW(),
    PRIMARY KEY (`EnrollmentID`),
    KEY `idx_se_student` (`StudentID`),
    KEY `idx_se_class` (`ClassID`),
    CONSTRAINT `fk_se_student` FOREIGN KEY (`StudentID`) REFERENCES `Users`(`UserID`),
    CONSTRAINT `fk_se_class`   FOREIGN KEY (`ClassID`)   REFERENCES `Classes`(`ClassID`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

CREATE TABLE IF NOT EXISTS `Timetable` (
    `TimetableID`  INT NOT NULL AUTO_INCREMENT,
    `ClassID`      INT NOT NULL,
    `SubjectID`    INT NOT NULL,
    `TeacherID`    INT NOT NULL,
    `DayOfWeek`    VARCHAR(15) NOT NULL,
    `StartTime`    TIME NOT NULL,
    `EndTime`      TIME NOT NULL,
    `RoomNumber`   VARCHAR(50) NULL,
    `Room`         VARCHAR(50) NULL,
    `AcademicYear` VARCHAR(20) NULL,
    `CreatedAt`    DATETIME NOT NULL DEFAULT NOW(),
    PRIMARY KEY (`TimetableID`),
    KEY `idx_tt_class`   (`ClassID`),
    KEY `idx_tt_subject` (`SubjectID`),
    KEY `idx_tt_teacher` (`TeacherID`),
    CONSTRAINT `fk_tt_class`   FOREIGN KEY (`ClassID`)   REFERENCES `Classes`(`ClassID`),
    CONSTRAINT `fk_tt_subject` FOREIGN KEY (`SubjectID`) REFERENCES `Subjects`(`SubjectID`),
    CONSTRAINT `fk_tt_teacher` FOREIGN KEY (`TeacherID`) REFERENCES `Users`(`UserID`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

CREATE TABLE IF NOT EXISTS `QRCodes` (
    `QRCodeID`  INT NOT NULL AUTO_INCREMENT,
    `TeacherID` INT NOT NULL,
    `SubjectID` INT NOT NULL,
    `ClassID`   INT NOT NULL,
    `QRToken`   VARCHAR(255) NOT NULL,
    `ExpiresAt` DATETIME NOT NULL,
    `IsUsed`    TINYINT(1) NOT NULL DEFAULT 0,
    `CreatedAt` DATETIME NOT NULL DEFAULT NOW(),
    PRIMARY KEY (`QRCodeID`),
    UNIQUE KEY `uq_qr_token` (`QRToken`),
    CONSTRAINT `fk_qr_teacher` FOREIGN KEY (`TeacherID`) REFERENCES `Users`(`UserID`),
    CONSTRAINT `fk_qr_subject` FOREIGN KEY (`SubjectID`) REFERENCES `Subjects`(`SubjectID`),
    CONSTRAINT `fk_qr_class`   FOREIGN KEY (`ClassID`)   REFERENCES `Classes`(`ClassID`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

CREATE TABLE IF NOT EXISTS `Attendance` (
    `AttendanceID`   INT NOT NULL AUTO_INCREMENT,
    `StudentID`      INT NOT NULL,
    `SubjectID`      INT NOT NULL,
    `ClassID`        INT NULL,
    `QRCodeID`       INT NULL,
    `AttendanceDate` DATE NOT NULL,
    `Status`         ENUM('Present','Absent','Late') NOT NULL DEFAULT 'Present',
    `MarkedAt`       DATETIME NOT NULL DEFAULT NOW(),
    PRIMARY KEY (`AttendanceID`),
    CONSTRAINT `fk_att_student` FOREIGN KEY (`StudentID`) REFERENCES `Users`(`UserID`),
    CONSTRAINT `fk_att_subject` FOREIGN KEY (`SubjectID`) REFERENCES `Subjects`(`SubjectID`),
    CONSTRAINT `fk_att_class`   FOREIGN KEY (`ClassID`)   REFERENCES `Classes`(`ClassID`),
    CONSTRAINT `fk_att_qr`      FOREIGN KEY (`QRCodeID`)  REFERENCES `QRCodes`(`QRCodeID`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

CREATE TABLE IF NOT EXISTS `Marks` (
    `MarkID`       INT NOT NULL AUTO_INCREMENT,
    `StudentID`    INT NOT NULL,
    `SubjectID`    INT NOT NULL,
    `ClassID`      INT NULL,
    `AcademicYear` VARCHAR(10)  NULL DEFAULT '2024-25',
    `CA1`          DECIMAL(5,2) NULL DEFAULT 0,
    `CA2`          DECIMAL(5,2) NULL DEFAULT 0,
    `CA3`          DECIMAL(5,2) NULL DEFAULT 0,
    `CA4`          DECIMAL(5,2) NULL DEFAULT 0,
    `CA5`          DECIMAL(5,2) NULL DEFAULT 0,
    `Midterm`      DECIMAL(5,2) NULL DEFAULT 0,
    `Endterm`      DECIMAL(5,2) NULL DEFAULT 0,
    `UpdatedBy`    INT NULL,
    `UpdatedAt`    DATETIME NULL DEFAULT NOW(),
    PRIMARY KEY (`MarkID`),
    CONSTRAINT `fk_marks_student` FOREIGN KEY (`StudentID`) REFERENCES `Users`(`UserID`),
    CONSTRAINT `fk_marks_subject` FOREIGN KEY (`SubjectID`) REFERENCES `Subjects`(`SubjectID`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

CREATE TABLE IF NOT EXISTS `StudyMaterials` (
    `MaterialID`  INT NOT NULL AUTO_INCREMENT,
    `SubjectID`   INT NOT NULL,
    `ClassID`     INT NULL,
    `TeacherID`   INT NOT NULL,
    `Title`       VARCHAR(255) NOT NULL,
    `Description` TEXT NULL,
    `FileName`    VARCHAR(255) NULL,
    `FilePath`    VARCHAR(500) NULL,
    `FileType`    VARCHAR(50)  NULL,
    `FileSize`    BIGINT NOT NULL DEFAULT 0,
    `IsPublished` TINYINT(1) NOT NULL DEFAULT 1,
    `UploadedAt`  DATETIME NOT NULL DEFAULT NOW(),
    PRIMARY KEY (`MaterialID`),
    CONSTRAINT `fk_sm_subject` FOREIGN KEY (`SubjectID`) REFERENCES `Subjects`(`SubjectID`),
    CONSTRAINT `fk_sm_teacher` FOREIGN KEY (`TeacherID`) REFERENCES `Users`(`UserID`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

CREATE TABLE IF NOT EXISTS `Exams` (
    `ExamID`         INT NOT NULL AUTO_INCREMENT,
    `SubjectID`      INT NOT NULL,
    `ClassID`        INT NULL,
    `TeacherID`      INT NOT NULL,
    `ExamTitle`      VARCHAR(255) NOT NULL,
    `ExamName`       VARCHAR(500) NULL,
    `ExamType`       VARCHAR(50)  NULL,
    `TotalMarks`     INT NOT NULL DEFAULT 100,
    `TotalQuestions` INT NOT NULL DEFAULT 0,
    `Duration`       INT NOT NULL DEFAULT 60,
    `StartTime`      VARCHAR(10)  NULL,
    `EndTime`        VARCHAR(10)  NULL,
    `ExamDate`       DATETIME NULL,
    `Instructions`   TEXT NULL,
    `IsPublished`    TINYINT(1) NOT NULL DEFAULT 0,
    `IsActive`       TINYINT(1) NOT NULL DEFAULT 1,
    `CreatedAt`      DATETIME NOT NULL DEFAULT NOW(),
    PRIMARY KEY (`ExamID`),
    CONSTRAINT `fk_exam_subject` FOREIGN KEY (`SubjectID`) REFERENCES `Subjects`(`SubjectID`),
    CONSTRAINT `fk_exam_teacher` FOREIGN KEY (`TeacherID`) REFERENCES `Users`(`UserID`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

CREATE TABLE IF NOT EXISTS `ExamQuestions` (
    `QuestionID`    INT NOT NULL AUTO_INCREMENT,
    `ExamID`        INT NOT NULL,
    `QuestionText`  TEXT NOT NULL,
    `OptionA`       VARCHAR(500) NULL,
    `OptionB`       VARCHAR(500) NULL,
    `OptionC`       VARCHAR(500) NULL,
    `OptionD`       VARCHAR(500) NULL,
    `CorrectAnswer` VARCHAR(10)  NULL,
    `Marks`         INT NOT NULL DEFAULT 1,
    `QuestionOrder` INT NOT NULL DEFAULT 1,
    `CreatedAt`     DATETIME NOT NULL DEFAULT NOW(),
    PRIMARY KEY (`QuestionID`),
    CONSTRAINT `fk_eq_exam` FOREIGN KEY (`ExamID`) REFERENCES `Exams`(`ExamID`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

CREATE TABLE IF NOT EXISTS `ExamSubmissions` (
    `SubmissionID`  INT NOT NULL AUTO_INCREMENT,
    `ExamID`        INT NOT NULL,
    `StudentID`     INT NOT NULL,
    `SubmittedAt`   DATETIME NOT NULL DEFAULT NOW(),
    `TotalScore`    DECIMAL(5,2)  NOT NULL DEFAULT 0,
    `MarksObtained` DECIMAL(10,2) NULL,
    `IsSubmitted`   TINYINT(1) NOT NULL DEFAULT 0,
    `Answers`       TEXT NULL,
    `CreatedAt`     DATETIME NOT NULL DEFAULT NOW(),
    PRIMARY KEY (`SubmissionID`),
    CONSTRAINT `fk_esub_exam` FOREIGN KEY (`ExamID`) REFERENCES `Exams`(`ExamID`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

CREATE TABLE IF NOT EXISTS `OnlineClasses` (
    `OnlineClassID` INT NOT NULL AUTO_INCREMENT,
    `SubjectID`     INT NOT NULL,
    `ClassID`       INT NULL,
    `TeacherID`     INT NOT NULL,
    `Title`         VARCHAR(255) NOT NULL,
    `Topic`         VARCHAR(500) NULL,
    `Description`   TEXT NULL,
    `MeetingLink`   VARCHAR(500) NULL,
    `ScheduledAt`   DATETIME NULL,
    `ScheduledDate` DATE NULL,
    `StartTime`     VARCHAR(10)  NULL,
    `EndTime`       VARCHAR(10)  NULL,
    `Duration`      INT NULL,
    `IsRecorded`    TINYINT(1) NOT NULL DEFAULT 0,
    `IsActive`      TINYINT(1) NOT NULL DEFAULT 1,
    `RecordingURL`  VARCHAR(500) NULL,
    `CreatedAt`     DATETIME NOT NULL DEFAULT NOW(),
    PRIMARY KEY (`OnlineClassID`),
    CONSTRAINT `fk_oc_subject` FOREIGN KEY (`SubjectID`) REFERENCES `Subjects`(`SubjectID`),
    CONSTRAINT `fk_oc_teacher` FOREIGN KEY (`TeacherID`) REFERENCES `Users`(`UserID`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

CREATE TABLE IF NOT EXISTS `FeeStructure` (
    `FeeStructureID` INT NOT NULL AUTO_INCREMENT,
    `DepartmentID`   INT NOT NULL,
    `Semester`       INT NOT NULL,
    `AcademicYear`   VARCHAR(20)   NULL,
    `TuitionFee`     DECIMAL(10,2) NOT NULL DEFAULT 0,
    `LibraryFee`     DECIMAL(10,2) NOT NULL DEFAULT 0,
    `LabFee`         DECIMAL(10,2) NOT NULL DEFAULT 0,
    `SportsFee`      DECIMAL(10,2) NOT NULL DEFAULT 0,
    `OtherFees`      DECIMAL(10,2) NOT NULL DEFAULT 0,
    `CreatedAt`      DATETIME NOT NULL DEFAULT NOW(),
    PRIMARY KEY (`FeeStructureID`),
    CONSTRAINT `fk_fee_dept` FOREIGN KEY (`DepartmentID`) REFERENCES `Departments`(`DepartmentID`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

CREATE TABLE IF NOT EXISTS `FeePayments` (
    `PaymentID`      INT NOT NULL AUTO_INCREMENT,
    `StudentID`      INT NOT NULL,
    `FeeStructureID` INT NOT NULL,
    `AmountPaid`     DECIMAL(10,2) NOT NULL,
    `PaymentDate`    DATETIME NOT NULL DEFAULT NOW(),
    `PaymentMode`    VARCHAR(50)  NULL,
    `TransactionID`  VARCHAR(100) NULL,
    `ReceiptNumber`  VARCHAR(100) NULL,
    `AcademicYear`   VARCHAR(10)  NOT NULL DEFAULT '2024-25',
    `Description`    VARCHAR(300) NULL,
    `Remarks`        VARCHAR(255) NULL,
    `CreatedAt`      DATETIME NOT NULL DEFAULT NOW(),
    PRIMARY KEY (`PaymentID`),
    CONSTRAINT `fk_fp_student` FOREIGN KEY (`StudentID`)      REFERENCES `Users`(`UserID`),
    CONSTRAINT `fk_fp_feestr`  FOREIGN KEY (`FeeStructureID`) REFERENCES `FeeStructure`(`FeeStructureID`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

CREATE TABLE IF NOT EXISTS `StudentCounts` (
    `StudentCountID` INT NOT NULL AUTO_INCREMENT,
    `DepartmentID`   INT NOT NULL,
    `Semester`       INT NOT NULL,
    `StudentCount`   INT NOT NULL DEFAULT 0,
    `AcademicYear`   VARCHAR(20) NULL,
    `CreatedAt`      DATETIME NOT NULL DEFAULT NOW(),
    PRIMARY KEY (`StudentCountID`),
    CONSTRAINT `fk_sc_dept` FOREIGN KEY (`DepartmentID`) REFERENCES `Departments`(`DepartmentID`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

CREATE TABLE IF NOT EXISTS `ActivityLogs` (
    `LogID`     INT NOT NULL AUTO_INCREMENT,
    `UserID`    INT NOT NULL,
    `Activity`  VARCHAR(100) NULL,
    `Details`   VARCHAR(500) NULL,
    `IPAddress` VARCHAR(50)  NULL,
    `CreatedAt` DATETIME NOT NULL DEFAULT NOW(),
    PRIMARY KEY (`LogID`),
    CONSTRAINT `fk_al_user` FOREIGN KEY (`UserID`) REFERENCES `Users`(`UserID`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

CREATE TABLE IF NOT EXISTS `Notifications` (
    `NotificationID` INT NOT NULL AUTO_INCREMENT,
    `UserID`         INT NULL,
    `StudentID`      INT NULL,
    `Title`          VARCHAR(255)  NOT NULL,
    `Message`        VARCHAR(1000) NULL,
    `Type`           VARCHAR(50)   NOT NULL DEFAULT 'General',
    `IsRead`         TINYINT(1)    NOT NULL DEFAULT 0,
    `CreatedAt`      DATETIME NOT NULL DEFAULT NOW(),
    PRIMARY KEY (`NotificationID`),
    KEY `idx_notif_user`    (`UserID`),
    KEY `idx_notif_student` (`StudentID`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

